sp_widget.client_script:
api.controller = function($scope, $rootScope) {
	/* widget controller */
	var c = this;

	c.onCancel = function() {
		$scope.$parent.$parent.$dismiss();
	};

	c.enableSubmitButton = function() {
		if (c.data.newRejectionReason === undefined) {
			c.data.isSubmitButtonDisabled = true;
		} else {
			c.data.isSubmitButtonDisabled = c.data.newRejectionReason.length === 0;
		}
	};

	c.onSubmit = function() {
		c.data.submit = true;
		$scope.data.newRejectionReason = c.data.newRejectionReason;
		$scope.server.update().then(function() {
			// DFCT0011121 - this was opened in a modal, broadcast that the modal closed by submitting form successfully
			$rootScope.$broadcast('sp.modal.form.complete');				
			$scope.$parent.$parent.$dismiss();
		});

	};

};

