// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: Tasker Modal - Delete Task
//------------------------------------------------------------------------------------------------------------------------
// 2.8.0 | 2022-06-27 | raj  | STRY0123191 - Warning Modal- Rejecting an Approval Subtask will close all "Approval Dependent Tasks"
//                      New Widget
// 2.8.0 | 2022-07-23 | raj  | DFCT0011029 - The decimal point  "." should NOT display on the  count in the "Rejection for Approval Task " modal 
//
// 2.8.0 | 2022-08-14 | raj  |  STRY0125927 - All Mark Complete modals- Add info message "Marking complete will delete Draft Tasks"
//                                          Changes in Server script and HTML
// 2.8.0 | 2022-08-22 | raj  | DFCT0011121 - (2 issues) General Information modal is "NOT"  closing on "Approval" task types upon clicking the "Reject"& "ReOpen" buttons from the warning modal. 
//                                          Changes in Client Controller
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options) {
	var tableRouteTaskInstance = 'x_153465_discovert_route_task_instance';

	main();

	function main() {
		if (input) {
			if (input.submit == true) {
				// run reject
				var grTasksReject = new GlideRecord(tableRouteTaskInstance);
				if (grTasksReject.get(input.taskSysId)) {
					grTasksReject.comments_dt = input.newRejectionReason;
					new Task_uiAction().uiAction_UpdateTaskAndResponseLog("Rejected", 'reject', grTasksReject);
				}
			} else {
				// copy to data[name] from input[name] || option[name]
				_optCopy(['rejectionReason', 'taskSysId']);
				_buildMessages();
				_setDataDefaults();
			}
		}
	}

	function _buildMessages() {
		// STRY0125927
		_getApprovalDependantsCount();
		data.cancelButtonText = gs.getMessage('cancel');
		data.submitButtonText = gs.getMessage('Tasker - Button - Reject');
		data.submitButtonTitle = gs.getMessage('Tasker - Rejects the Approval and closes dependent approval task');

		data.msgBody2 = gs.getMessage('Warning');
		data.msgBody3 = gs.getMessage('Tasker - You are about to reject an Approval Subtask');
		// STRY0125927
		data.msgBody4 = gs.getMessage('Tasker - This will also close all {0} Approval Tasks dependent on this task', [data.approvalDependantsCount.toString()]);
		// STRY0125927
		data.msgDraftCount = gs.getMessage('Tasker - You have {0} draft tasks', [data.approvalDraftDependantsCount.toString()]);
		data.msgDraftInfo = gs.getMessage('Tasker - This will automatically delete ALL draft subtasks as well');

		data.msgBody5 = gs.getMessage('Tasker - Approval Parent Tasks are dependent on Approval Subtasks. Approval Next-Task Orders are dependent on Previous-Task Orders');
		data.msgBody6 = gs.getMessage('Tasker - Rejection Reason');
		data.msgBody7 = gs.getMessage('Tasker - Type your rejection reason here');
		data.msgBody8 = gs.getMessage('Tasker - Are you sure you would like to continue?');
	}

	function _getApprovalDependantsCount() {
		var strCount = "";
		var approvalDependantsCount = 0;
		var approvalDraftDependantsCount = 0;
		var taskerHelpers = new TaskerHelpers();
		// STRY0125927
		approvalDependantsCount = taskerHelpers.getActiveApprovalDependantsCount(data.taskSysId);
		approvalDraftDependantsCount = taskerHelpers.getDraftApprovalDependantsCount(data.taskSysId);
		data.approvalDraftDependantsCount = approvalDraftDependantsCount;
		data.approvalDependantsCount = approvalDependantsCount - approvalDraftDependantsCount;

	}


	// copy to data from input or options
	function _optCopy(names) {
		names.forEach(function(name) {
			data[name] = input[name] || options[name];
		});
	}

	function _setDataDefaults() {
		data.isSubmitButtonDisabled = true;
		data.submit = false;
		data.newRejectionReason = data.rejectionReason;
		if (data.newRejectionReason === undefined) {
			data.isSubmitButtonDisabled = true;
		} else {
			data.isSubmitButtonDisabled = data.newRejectionReason.length === 0;
		}
	}
})($sp, input, data, options);
